import { Component } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { Router } from '@angular/router';
import {
  IonContent, IonHeader, IonToolbar, IonTitle,
  IonButton, IonItem, IonInput, IonList, IonToast, IonBackButton, IonButtons,
} from '@ionic/angular/standalone';
import { AuthService } from '../../services/auth.service';

@Component({
  selector: 'app-login',
  standalone: true,
  imports: [
    CommonModule, FormsModule,
    IonContent, IonHeader, IonToolbar, IonTitle,
    IonButton, IonItem, IonInput, IonList, IonToast, IonBackButton, IonButtons,
  ],
  styles: [`
    .login-container {
      display: flex;
      flex-direction: column;
      align-items: center;
      justify-content: center;
      min-height: 70vh;
      padding: 32px 24px;
      text-align: center;
    }
    .login-emoji {
      font-size: 56px;
      margin-bottom: 24px;
      line-height: 1;
    }
    .login-title {
      font-size: 26px;
      font-weight: 700;
      color: var(--ion-text-color, #1a1a2e);
      margin-bottom: 8px;
    }
    .login-subtitle {
      font-size: 14px;
      color: var(--ion-color-medium);
      margin-bottom: 32px;
      line-height: 1.5;
    }
    .field-label {
      font-size: 12px;
      font-weight: 600;
      color: var(--ion-color-medium);
      letter-spacing: 0.5px;
      text-transform: uppercase;
      margin-bottom: 4px;
      text-align: left;
      width: 100%;
    }
    .input-block {
      width: 100%;
      margin-bottom: 24px;
    }
  `],
  template: `
    <ion-header>
      <ion-toolbar>
        <ion-buttons slot="start">
          <ion-back-button defaultHref="/onboarding/ciudad"></ion-back-button>
        </ion-buttons>
        <ion-title>Iniciar sesión</ion-title>
      </ion-toolbar>
    </ion-header>

    <ion-content>
      <div class="login-container">
        <div class="login-emoji">🎶</div>
        <div class="login-title">¡Bienvenido de vuelta!</div>
        <div class="login-subtitle">
          Introduce tu alias para volver a la pista.
        </div>

        <div class="input-block">
          <div class="field-label">Tu alias</div>
          <ion-list lines="none" style="border-radius: 10px; overflow: hidden;">
            <ion-item>
              <ion-input
                [(ngModel)]="alias"
                placeholder="Ej. salsa_king"
                autocomplete="off"
                (keyup.enter)="login()">
              </ion-input>
            </ion-item>
          </ion-list>
        </div>

        <ion-button
          expand="block"
          style="width: 100%;"
          [disabled]="!alias.trim() || loading"
          (click)="login()">
          {{ loading ? 'Entrando...' : 'Entrar' }}
        </ion-button>
      </div>

      <ion-toast
        [isOpen]="!!error"
        [message]="error"
        duration="3000"
        color="danger"
        (didDismiss)="error = ''">
      </ion-toast>
    </ion-content>
  `,
})
export class LoginPage {
  alias = '';
  loading = false;
  error = '';

  constructor(
    private authService: AuthService,
    private router: Router,
  ) {}

  login(): void {
    if (!this.alias.trim() || this.loading) return;
    this.loading = true;
    this.authService.login(this.alias.trim()).subscribe({
      next: () => {
        this.router.navigate(['/tabs/home'], { replaceUrl: true });
      },
      error: (err) => {
        this.loading = false;
        this.error = err?.error?.message ?? 'Alias no encontrado.';
      },
    });
  }
}
